insert into catalog.food_concepts (canonical_name, canonical_name_normalized, category_id, scientific_name, status, confidence_level)
select c->>'cn', c->>'cnn', cat.id, nullif(c->>'sci',''), 'published', 'B'
from _c join catalog.food_categories cat on cat.code = c->>'cat'
on conflict (canonical_name_normalized) do nothing;
drop table _c;
